		desc_kr = '각 대턴이 끝날 때마다, 플레이어의 포켓몬 중 하나가 체력과 분노를 무작위로 회복합니다.',
		desc_pt = 'No final de cada turno grande, um dos Pokémon do jogador terá seus HP e raiva restaurados aleatoriamente.',
		desc_th = 'เมื่อจบแต่ละเทิร์นใหญ่ พลังชีวิตและพลังโกรธของโปเกมอนของผู้เล่นหนึ่งตัวจะได้รับการฟื้นฟูแบบสุ่ม',
		rarity = 1,
		groupID = 100000,
